member.example:
Bind the character validation of a TMP_InputField using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldCharacterValidationBinder _characterValidation;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.CharacterValidation _characterValidation;
    }


Bind the character validation of a TMP_InputField by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldCharacterValidationBinder CharacterValidation =>
            new(_inputField);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.CharacterValidation _characterValidation;
    }

Switch the character validation of a TMP_InputField between two values using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldCharacterValidationSwitcherBinder _isEmailValidation;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isEmailValidation;
    }


Switch the character validation of a TMP_InputField between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldCharacterValidationSwitcherBinder IsEmailValidation => new(
            _inputField,
            TMP_InputField.CharacterValidation.EmailAddress,
            TMP_InputField.CharacterValidation.None);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isEmailValidation;
    }
